import{_ as t,o as e,c as o,ak as r}from"./chunks/framework.v1e5hYbe.js";const p=JSON.parse('{"title":"基本的な使い方","description":"","frontmatter":{},"headers":[],"relativePath":"guide/how-to-use.md","filePath":"guide/how-to-use.md"}'),l={name:"guide/how-to-use.md"};function i(d,a,h,n,c,s){return e(),o("div",null,[...a[0]||(a[0]=[r('<h1 id="基本的な使い方" tabindex="-1">基本的な使い方 <a class="header-anchor" href="#基本的な使い方" aria-label="Permalink to &quot;基本的な使い方&quot;">​</a></h1><p>Lyra Menu Managerの基本操作について</p><h2 id="ウィンドウを開く" tabindex="-1">ウィンドウを開く <a class="header-anchor" href="#ウィンドウを開く" aria-label="Permalink to &quot;ウィンドウを開く&quot;">​</a></h2><p>Unity上部のメニューバーから <code>Tools</code> &gt; <code>Lyra</code> &gt; <code>Menu Manager</code> をクリックしてウィンドウを開きます。</p><div class="tip custom-block"><p class="custom-block-title">💡 推奨レイアウト</p><p>大きめのUI構成のため、独立したウィンドウとして使用することをおすすめします。</p></div><h2 id="アバターを読み込む" tabindex="-1">アバターを読み込む <a class="header-anchor" href="#アバターを読み込む" aria-label="Permalink to &quot;アバターを読み込む&quot;">​</a></h2><p>ウィンドウのAvatar欄に追加するか、ヒエラルキータブから、<code>VRC Avatar Descriptor</code> がアタッチされているアバタールートをアバター追加エリアに直接D&amp;Dしてください。</p><p>その後自動でメニュー構造が解析され、その時点でのメニュー情報が表示されます。</p><h2 id="メニューの編集・並び替え" tabindex="-1">メニューの編集・並び替え <a class="header-anchor" href="#メニューの編集・並び替え" aria-label="Permalink to &quot;メニューの編集・並び替え&quot;">​</a></h2><h3 id="アイテムの選択と詳細確認" tabindex="-1">アイテムの選択と詳細確認 <a class="header-anchor" href="#アイテムの選択と詳細確認" aria-label="Permalink to &quot;アイテムの選択と詳細確認&quot;">​</a></h3><p>リングメニュー内のアイテムをクリックすると選択状態となり、下部に名称やアイコンなどを設定・確認できる詳細パネルが表示されます。</p><h3 id="移動・並び替え" tabindex="-1">移動・並び替え <a class="header-anchor" href="#移動・並び替え" aria-label="Permalink to &quot;移動・並び替え&quot;">​</a></h3><table tabindex="0"><thead><tr><th>操作</th><th>方法</th></tr></thead><tbody><tr><td>順番の入れ替え</td><td>入れ替え先の境界へドロップ</td></tr><tr><td>サブメニューに移動</td><td>サブメニューの上でドロップ</td></tr><tr><td>親階層へ移動</td><td>中心に向かってドロップ</td></tr></tbody></table><h3 id="名前・アイコンの変更" tabindex="-1">名前・アイコンの変更 <a class="header-anchor" href="#名前・アイコンの変更" aria-label="Permalink to &quot;名前・アイコンの変更&quot;">​</a></h3><ul><li>詳細パネルから名前とアイコン画像の変更が可能です。</li><li>リングメニュー内の文字をダブルクリックすることでも、名前の編集が行えます。</li></ul><h3 id="フォルダ作成-インベントリ操作" tabindex="-1">フォルダ作成 / インベントリ操作 <a class="header-anchor" href="#フォルダ作成-インベントリ操作" aria-label="Permalink to &quot;フォルダ作成 / インベントリ操作&quot;">​</a></h3><ul><li><strong>フォルダ作成</strong></li></ul><p>コンテキストメニューから&quot;フォルダ作成&quot;ボタンを押す、または通常UI時に空スロットでダブルクリックすることでサブフォルダを作成できます。</p><ul><li><strong>インベントリへ退避</strong></li></ul><p>不要なメニューは、左パネルのインベントリにドラッグするか、右クリックから一時退避・削除が可能です。</p><h2 id="変更の保存" tabindex="-1">変更の保存 <a class="header-anchor" href="#変更の保存" aria-label="Permalink to &quot;変更の保存&quot;">​</a></h2><p>メニューの並びや名前の変更が完了したら、必ず保存をクリックして変更を確定してください。</p><div class="warning custom-block"><p class="custom-block-title">⚠️ 注意</p><p>保存せずにアバターのプレハブを更新したり、シーンを移動すると編集内容が失われる場合があります。</p></div><div class="info custom-block"><p class="custom-block-title">💾 保存の仕組み</p><p>保存を実行すると、アバターのルート要素に <a href="/MenuManager/guide/component.html"><code>MenuLayoutData</code></a> コンポーネントがアタッチされ、そこにレイアウト情報が書き込まれます。</p></div><hr><h2 id="次のステップ" tabindex="-1">次のステップ <a class="header-anchor" href="#次のステップ" aria-label="Permalink to &quot;次のステップ&quot;">​</a></h2><ul><li><a href="/MenuManager/guide/component.html">コンポーネント</a> — 各コンポーネントの設定項目について</li><li><a href="/MenuManager/guide/technical-details/architecture.html">技術仕様: アーキテクチャ概要</a> — 内部の仕組みを詳しく知りたい方へ</li></ul>',27)])])}const b=t(l,[["render",i]]);export{p as __pageData,b as default};
